import { useState, useEffect } from "react";
import requests from "../helpers/requests";
import { Card, Form, Button, Modal } from "react-bootstrap";

function Login(props) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [show, setShow] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const onSubmit = async (ev) => {
    ev.preventDefault();
    const response = await requests.post("/singin", { email, password });
    if (response.error) {
      setErrorMessage(response.message);
      setShow(true);
    } else {
      props.navigation.go("Clients");
    }
  };

  useEffect(() =>{
    if(props.isAuth) {
      props.navigation.go('Clients')
    }
  },[props])


  return (
    <>
      <Modal
        size="lg"
        aria-labelledby="contained-modal-title-vcenter"
        centered
        show={show}
        onHide={() => setShow(false)}
      >
        <Modal.Header closeButton>
          <Modal.Title>Ocurrio un error</Modal.Title>
        </Modal.Header>
        <Modal.Body>{errorMessage}</Modal.Body>
      </Modal>
      <div className="login-container p-2">
        <Card className="login-card">
          <Form onSubmit={onSubmit}>
            <Card.Header>
              <Card.Title className="text-center">TlaCrm</Card.Title>
              <Card.Subtitle className="text-center">
                Inicio de Sesión
              </Card.Subtitle>
            </Card.Header>

            <Card.Body>
              <Form.Group className="mb-3" controlId="email">
                <Form.Label>Email:</Form.Label>
                <Form.Control
                  type="email"
                  placeholder="Ingresa tu correo"
                  required
                  value={email}
                  onChange={(ev) => setEmail(ev.target.value)}
                />
              </Form.Group>

              <Form.Group className="mb-3" controlId="password">
                <Form.Label>Password:</Form.Label>
                <Form.Control
                  type="password"
                  placeholder="Ingresa tu contraseña"
                  required
                  value={password}
                  onChange={(ev) => setPassword(ev.target.value)}
                />
              </Form.Group>
            </Card.Body>
            <Card.Footer>
              <Button type="submit" variant="primary">
                Atenticación
              </Button>
            </Card.Footer>
          </Form>
        </Card>
      </div>
    </>
  );
}

export default Login;
